import{_ as p,o as e,c as i,ae as s}from"./chunks/framework.Czhw_PXq.js";const _=JSON.parse('{"title":"ensp wifi配置笔记","description":"","frontmatter":{"aside":"left"},"headers":[],"relativePath":"note/ensp-acap上线.md","filePath":"note/ensp-acap上线.md"}'),n={name:"note/ensp-acap上线.md"};function r(t,a,c,o,l,d){return e(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="ensp-wifi配置笔记" tabindex="-1">ensp wifi配置笔记 <a class="header-anchor" href="#ensp-wifi配置笔记" aria-label="Permalink to &quot;ensp wifi配置笔记&quot;">​</a></h1><h2 id="_1-让ap上线" tabindex="-1">1.让ap上线 <a class="header-anchor" href="#_1-让ap上线" aria-label="Permalink to &quot;1.让ap上线&quot;">​</a></h2><p>（1）ap通过ac的dhcp发放获取ip地址</p><p>​ 创建vlan 在ac的vlanif上面配置dhcp ：dhcp select interface</p><p>（2）通过capwap隧道上线</p><p>​ capwap source intface vlanif 100 //通过100管理这条隧道</p><p>​ ap-group name hcia //创建ap组来统一管理</p><p>（3）让ap设备进入ap组管理</p><p>​ ap-id 1 ap-mac MAC地址 //apmac认证</p><p>​ ap-name ap1 //ap设备命名ap1</p><p>​ ap-group hcia //把设备分到组里面统一管理</p><h2 id="_2-配置无线参数" tabindex="-1">2.配置无线参数 <a class="header-anchor" href="#_2-配置无线参数" aria-label="Permalink to &quot;2.配置无线参数&quot;">​</a></h2><p>ssid模板：</p><p>ssid-profile name wlan-ssid</p><p>ssid huawei</p><p>安全模板:</p><p>security-profile name wlan-sec</p><p>security wpa-wpa2 psk pass-phrass 密码 aes</p><p>vap模板:</p><p>vap-profile name wlan-vap</p><p>service-vlan vlan-id 10</p><p>加组</p><p>ssid-profile wlan-ssid</p><p>security-profile wlan-sec</p><p>通过ap-grout组统一管理调用vap模板:</p><p>ap -group name hcia</p><p>vap-profile wlan-vap wlan 1 radio all</p>',27)])])}const h=p(n,[["render",r]]);export{_ as __pageData,h as default};
